import numpy as np

def parse_panel(grid, col_start, col_end, row_start=0, row_end=None):
    """Parse a panel (left or right) to extract Pattern A, middle shape, Box C, Box D."""
    if row_end is None:
        row_end = len(grid)

    panel = [row[col_start:col_end+1] for row in grid[row_start:row_end]]
    H = len(panel)
    W = len(panel[0])

    # Find horizontal 6 separator
    h_sep = None
    for r in range(H):
        if all(panel[r][c] == 6 for c in range(W)):
            h_sep = r
            break

    # Pattern A: find bordered region at top
    # First row should be all 0s
    # Find the pattern box: rows between first all-0 row and next all-0 row
    pat_start = None
    pat_end = None
    for r in range(h_sep):
        row_vals = [panel[r][c] for c in range(W)]
        has_nonzero = any(v != 0 for v in row_vals)
        if has_nonzero and pat_start is None:
            pat_start = r
        elif not has_nonzero and pat_start is not None:
            pat_end = r
            break

    # Find inner bounds of Pattern A (excluding 0 borders)
    inner_rstart = pat_start
    inner_rend = pat_end
    inner_cstart = 0
    inner_cend = W

    # Find col bounds
    for c in range(W):
        if any(panel[r][c] != 0 for r in range(inner_rstart, inner_rend)):
            inner_cstart = c
            break
    for c in range(W-1, -1, -1):
        if any(panel[r][c] != 0 for r in range(inner_rstart, inner_rend)):
            inner_cend = c + 1
            break

    pattern_a = []
    for r in range(inner_rstart, inner_rend):
        pattern_a.append(panel[r][inner_cstart:inner_cend])

    # Middle section: between pattern A bottom border and h_sep
    # Find non-zero cells
    mid_rows = []
    for r in range(pat_end, h_sep):
        mid_rows.append(panel[r])

    # Find bounding box of non-zero values in middle section
    mid_min_r, mid_max_r = None, None
    mid_min_c, mid_max_c = None, None
    for r in range(len(mid_rows)):
        for c in range(W):
            if mid_rows[r][c] != 0:
                if mid_min_r is None:
                    mid_min_r = r
                mid_max_r = r
                if mid_min_c is None or c < mid_min_c:
                    mid_min_c = c
                if mid_max_c is None or c > mid_max_c:
                    mid_max_c = c

    middle_pattern = []
    if mid_min_r is not None:
        for r in range(mid_min_r, mid_max_r + 1):
            row = []
            for c in range(mid_min_c, mid_max_c + 1):
                row.append(1 if mid_rows[r][c] != 0 else 0)
            middle_pattern.append(row)

    # Box C and Box D: below h_sep
    # Find second h_sep (all 6s)
    h_sep2 = None
    for r in range(h_sep + 1, H):
        if all(panel[r][c] == 6 for c in range(W)):
            h_sep2 = r
            break

    # Box C inner: between h_sep and h_sep2, excluding 6-borders
    # Find the inner area (non-6 cells)
    boxc_inner = []
    for r in range(h_sep + 1, h_sep2):
        row = []
        for c in range(W):
            if panel[r][c] != 6:
                row.append(panel[r][c])
        boxc_inner.append(row)

    # Find 4 position in Box C
    four_pos = None
    for r in range(len(boxc_inner)):
        for c in range(len(boxc_inner[r])):
            if boxc_inner[r][c] == 4:
                four_pos = (r, c)

    # Box D inner: after h_sep2
    boxd_inner = []
    for r in range(h_sep2 + 1, H):
        row = []
        for c in range(W):
            if panel[r][c] != 6:
                row.append(panel[r][c])
        boxd_inner.append(row)

    # Find 7 positions in Box D
    seven_positions = []
    for r in range(len(boxd_inner)):
        for c in range(len(boxd_inner[r])):
            if boxd_inner[r][c] == 7:
                seven_positions.append((r, c))

    # Determine rotation from Box C 4 position
    # (0,0)=TL→0°, (0,end)=TR→90°CW, (end,end)=BR→180°, (end,0)=BL→270°CW
    bc_rows = len(boxc_inner)
    bc_cols = len(boxc_inner[0]) if boxc_inner else 0

    r4, c4 = four_pos
    if r4 == 0 and c4 == 0:
        rotation = 0
    elif r4 == 0 and c4 == bc_cols - 1:
        rotation = 1  # 90° CW
    elif r4 == bc_rows - 1 and c4 == bc_cols - 1:
        rotation = 2  # 180°
    elif r4 == bc_rows - 1 and c4 == 0:
        rotation = 3  # 270° CW
    else:
        rotation = 0  # fallback

    return {
        'pattern_a': pattern_a,
        'middle_pattern': middle_pattern,
        'rotation': rotation,
        'four_pos': four_pos,
        'seven_positions': seven_positions,
    }

