print("Example 1 panel:")
print(f"  Pattern A: {result['pattern_a']}")
print(f"  Middle pattern: {result['middle_pattern']}")
print(f"  Rotation: {result['rotation'] * 90}°")
print(f"  Four pos: {result['four_pos']}")
print(f"  Seven pos: {result['seven_positions']}")

