    # Find vertical 6-separators
    vseps = []
    for c in range(W):
        if all(grid[r][c] == 6 for r in range(H)):
            vseps.append(c)

    # Determine panels and canvas
    panels = []
    if len(vseps) == 1:
        panels.append({'col_start': 0, 'col_end': vseps[0] - 1})
        canvas_col_start = vseps[0] + 1
        canvas_col_end = W - 1
    elif len(vseps) == 2:
