        panel_data = parse_panel(grid, panel_info['col_start'], panel_info['col_end'])

        tile = swap_colors(panel_data['pattern_a'])
        tile_h = len(tile)
        tile_w = len(tile[0])

        rotated_mask = rotate_pattern(panel_data['middle_pattern'], panel_data['rotation'])
        mask_rows = len(rotated_mask)
        mask_cols = len(rotated_mask[0])

        grid_h = mask_rows * tile_h
        grid_w = mask_cols * tile_w

        rotation = panel_data['rotation']
        if rotation == 0:
            start_row = 0
            start_col = 0
        elif rotation == 1:
            start_row = 0
            start_col = canvas_W - grid_w
        elif rotation == 2:
            start_row = H - grid_h
            start_col = canvas_W - grid_w
        elif rotation == 3:
            start_row = H - grid_h
            start_col = 0

        for tr in range(mask_rows):
            for tc in range(mask_cols):
                if rotated_mask[tr][tc] != 0:
                    for dr in range(tile_h):
                        for dc in range(tile_w):
                            r = start_row + tr * tile_h + dr
                            c = start_col + tc * tile_w + dc
                            if 0 <= r < H and 0 <= c < canvas_W:
                                canvas[r][c] = tile[dr][dc]

    return canvas

